import { Grid } from "@mui/material";
import { Typography } from "@mui/material";
import { Chip, Avatar } from "@mui/material";
import React from "react";
import collage from  "../../items/Frame5.jpg";
import {Box,Button} from "@mui/material/core";
import SendIcon from '@mui/icons-material/Send';
import SensorReadings from "../SensorReadings/SensorReadings"
const BasicInfo = () => {
  // const theme = createTheme({
  //   typography: {
  //     fontFamily: ["Inter"],
  //   },
  // });
  return (
    <>
      <Grid container>
        <Grid item md={6} xs={12} sx={{ p: { md: 7, xs: 3 } }}>
          <Typography variant="h4" fontWeight={700} sx={{textAlign : {xs : "center", md:"left"}}} gutterBottom>
            End-to-End content needs for you. 
          </Typography>
          <Typography variant="h6" sx={{textAlign : {xs : "center", md:"left"}}}>
          Colourisko offers a one-stop shop for content-related services.
Leverage the network of our writers to get the best content fast. Unlimited revisions, quality content, multiple checks and fast deliveries!

          </Typography>
        </Grid>
        <Grid item1 md={4} xs={12} sx={{ p: { md: 7, xs: 3 } }}>
        <Avatar
            variant={"rounded"}
            alt="The image"
            src={collage}
            style={{
              width: 450,
              height: 200,
              background: "FFFFFF",

            }}
          />
          <Box m={2} pt={3}>
        <Button  variant="contained" endIcon={<SendIcon />}>
         Join Creator's Community
        </Button>
        </Box>
        </Grid>
      </Grid>
      <SensorReadings/>
    </>
  );
};

export default BasicInfo;
